/**
 * Notification model and related types.
 *
 * Architectural Decision: Event-Driven Notification System
 * =========================================================
 * Pattern: EventBus with typed subscribers and pluggable adapters.
 *
 * How it works:
 * 1. Domain services (OrderService, UserService) emit events via EventBus.
 * 2. NotificationService subscribes to relevant events on the EventBus.
 * 3. When an event arrives, NotificationService builds a NotificationPayload
 *    and dispatches it through all registered NotificationAdapter instances.
 * 4. Each adapter (email, webhook, in-app, SMS, etc.) implements the
 *    NotificationAdapter interface and handles delivery for its channel.
 *
 * Why event-driven over direct calls:
 * - Loose coupling: domain services don't know about notifications.
 * - Open for extension: add new notification channels by adding adapters,
 *   not by modifying existing services.
 * - Testable: EventBus provides an event log; adapters can be stubbed.
 * - Consistent: one pattern for all cross-service communication.
 *
 * Constraints (for all developers building on this foundation):
 * - All notifications MUST go through EventBus.emit() → NotificationService.
 *   Never call an adapter directly from a domain service.
 * - All delivery adapters MUST implement the NotificationAdapter interface.
 * - All notification types MUST be registered in the NotificationType union.
 * - NotificationPayload is the canonical shape passed to every adapter.
 */

/**
 * Supported notification types. Extend this union as new notification
 * triggers are added.
 */
export type NotificationType =
  | 'order:confirmation'
  | 'order:status-update'
  | 'user:welcome'
  | 'user:profile-updated';

/**
 * Supported delivery channels. Each channel maps to a NotificationAdapter.
 */
export type NotificationChannel = 'email' | 'in-app' | 'webhook' | 'sms';

/**
 * The payload passed to notification adapters for delivery.
 * This is the single contract between NotificationService and all adapters.
 */
export interface NotificationPayload {
  /** Unique notification type for routing and templating. */
  type: NotificationType;
  /** Recipient identifier (e.g., email address, user ID). */
  recipient: string;
  /** Short subject/title for the notification. */
  subject: string;
  /** Notification body content. */
  body: string;
  /** Arbitrary metadata for adapter-specific rendering. */
  metadata?: Record<string, unknown>;
}

/**
 * A persisted notification record (after delivery attempt).
 */
export interface Notification {
  id: string;
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  subject: string;
  body: string;
  status: 'sent' | 'failed';
  sentAt: Date;
  metadata?: Record<string, unknown>;
}

/**
 * NotificationAdapter — interface that all notification delivery adapters
 * must implement.
 *
 * Constraint: Every notification channel (email, webhook, SMS, in-app, etc.)
 * MUST have an adapter that implements this interface. Adapters are registered
 * with the NotificationService, which dispatches payloads to all of them.
 *
 * Adapters are responsible for:
 * - Accepting a NotificationPayload and delivering it via their channel.
 * - Returning a boolean indicating success (true) or failure (false).
 * - Handling their own retries/error logging internally.
 */

import type { NotificationChannel, NotificationPayload } from '../models/notification.js';

export interface NotificationAdapter {
  /** The channel this adapter handles. */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this adapter's channel.
   * @returns true if delivery succeeded, false otherwise.
   */
  send(payload: NotificationPayload): Promise<boolean>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is currently a stub that logs email sends in-memory rather than
 * connecting to a real SMTP server or email API. The interface is real
 * and production adapters should replace the send() implementation.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationPayload } from '../models/notification.js';
import type { NotificationChannel } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailNotificationAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  /**
   * Send an email notification.
   * Stub implementation: stores the email in memory and returns true.
   */
  async send(payload: NotificationPayload): Promise<boolean> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    const email: SentEmail = {
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
    };

    this.sentEmails.push(email);
    return true;
  }

  /**
   * Get all emails sent through this adapter. Useful for testing.
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — orchestrates notification delivery in response
 * to domain events received via EventBus.
 *
 * Architecture: Event-Driven with Pluggable Adapters
 * ====================================================
 * - Subscribes to domain events on the EventBus (the ONLY entry point).
 * - Translates events into NotificationPayload objects.
 * - Dispatches payloads to all registered NotificationAdapter instances.
 * - Persists a Notification record for each delivery attempt.
 *
 * Constraints:
 * - All event subscriptions happen in registerHandlers(). To add a new
 *   notification trigger, add a handler there and a corresponding
 *   NotificationType in src/models/notification.ts.
 * - Never call adapters directly from domain services — always go
 *   through EventBus → NotificationService.
 * - Adapters are registered via registerAdapter(). At least one adapter
 *   must be registered for notifications to be delivered.
 *
 * Depends on:
 * - EventBus (event system) for receiving ALL domain events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationPayload,
  NotificationType,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: NotificationAdapter[] = [];

  constructor(private eventBus: EventBus) {
    this.registerHandlers();
  }

  /**
   * Register a notification adapter for delivery.
   * Notifications will be dispatched to all registered adapters.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.adapters.push(adapter);
    this.logger.info(`Registered adapter: ${adapter.channel}`);
  }

  /**
   * Register event handlers for all notification triggers.
   * This is the ONLY place where EventBus subscriptions are created
   * for notifications.
   */
  private registerHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send confirmation to user.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    this.logger.info(`Sending order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.dispatchNotification({
      type: 'order:confirmation',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    this.logger.info(
      `Sending status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    await this.dispatchNotification({
      type: 'order:status-update',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
    });
  }

  /**
   * Dispatch a notification payload to all registered adapters and
   * persist a record for each delivery attempt.
   */
  private async dispatchNotification(payload: NotificationPayload): Promise<void> {
    if (this.adapters.length === 0) {
      // No adapters registered — store as in-app notification
      this.persistNotification(payload, 'in-app', true);
      return;
    }

    for (const adapter of this.adapters) {
      const success = await adapter.send(payload);
      this.persistNotification(payload, adapter.channel, success);
    }
  }

  /**
   * Persist a notification record after a delivery attempt.
   */
  private persistNotification(
    payload: NotificationPayload,
    channel: Notification['channel'],
    success: boolean,
  ): void {
    const notification: Notification = {
      id: generateNotificationId(),
      type: payload.type,
      channel,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      status: success ? 'sent' : 'failed',
      sentAt: new Date(),
      metadata: payload.metadata,
    };
    this.notifications.push(notification);
    this.logger.info(`Notification ${notification.id} [${channel}] to ${payload.recipient}: ${notification.status}`);
  }

  /**
   * Get all notification records.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get notifications filtered by type.
   */
  getNotificationsByType(type: NotificationType): Notification[] {
    return this.notifications.filter((n) => n.type === type);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all notifications (useful for testing).
   */
  clearNotifications(): void {
    this.notifications = [];
  }
}

